<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { getReadingDetail, setReadingSaved } from '@/api/readings'
import type { ReadingDetail } from '@/types/reading'
const route=useRoute();const router=useRouter();const reading=ref<ReadingDetail|null>(null);const loading=ref(true);const error=ref('');const id=computed(()=>String(route.params.readingId??''))
async function load(){loading.value=true;try{reading.value=await getReadingDetail(id.value)}catch(e){error.value=e instanceof Error?e.message:'Could not open this reading.'}finally{loading.value=false}}
async function toggle(){if(!reading.value)return;const old=reading.value.saved;reading.value.saved=!old;try{await setReadingSaved(reading.value.id,reading.value.saved)}catch{reading.value.saved=old}}
function guide(){void router.push({name:'ai-guide',query:{readingId:id.value}})}
onMounted(()=>void load())
</script>
<template><main class="page"><p v-if="loading">Returning to this reflection…</p><section v-else-if="error"><p>{{error}}</p><button @click="load">Try again</button></section><template v-else-if="reading"><header><p>{{reading.spread_type.replace('_',' ')}}</p><h1>{{reading.title}}</h1><blockquote v-if="reading.question">“{{reading.question}}”</blockquote><div><button @click="toggle">{{reading.saved?'Saved':'Save reading'}}</button><button @click="guide">Talk this through →</button></div></header><section class="cards"><article v-for="card in reading.cards" :key="`${card.card_id}-${card.position}`"><div class="img"><img v-if="card.image_url" :src="card.image_url" :alt="card.name" :class="{reversed:card.reversed}"/></div><div><small>{{card.position||'Guidance'}}</small><h2>{{card.name}} <span v-if="card.reversed">— Reversed</span></h2><p>{{card.interpretation}}</p></div></article></section><section v-if="reading.synthesis||reading.advice" class="closing"><div v-if="reading.synthesis"><p>THE THREAD BETWEEN THEM</p><h2>{{reading.synthesis}}</h2></div><div v-if="reading.advice"><p>TAKE WITH YOU</p><h2>{{reading.advice}}</h2></div></section></template></main></template>
<style scoped>.page{min-height:100vh;padding:76px clamp(24px,8vw,140px) 110px;background:#0e1d51;color:#f7f5ef}header>p,.closing p,.cards small{font-size:.66rem;font-weight:700;letter-spacing:.18em;text-transform:uppercase;color:#91a3ce}header h1{margin:18px 0;font-size:clamp(3.2rem,8vw,8.5rem);font-weight:450;line-height:.88;letter-spacing:-.07em}blockquote{max-width:700px;margin:34px 0;color:#aeb9d2;font-size:1.15rem}button{padding:12px 18px;border:1px solid rgba(255,255,255,.28);border-radius:999px;background:transparent;color:inherit;cursor:pointer}.cards{display:grid;gap:60px;margin-top:100px}.cards article{display:grid;grid-template-columns:minmax(220px,340px) minmax(0,680px);gap:clamp(34px,6vw,90px);align-items:center}.img{aspect-ratio:2/3;overflow:hidden;border-radius:24px;background:rgba(255,255,255,.06)}.img img{width:100%;height:100%;object-fit:cover}.img img.reversed{transform:rotate(180deg)}.cards h2,.closing h2{margin:12px 0;font-size:clamp(1.7rem,3vw,3.5rem);font-weight:450}.cards p{color:#aeb9d2;line-height:1.85}.closing{display:grid;grid-template-columns:repeat(2,1fr);gap:26px;margin-top:100px}.closing>div{padding:34px;border-radius:28px;background:rgba(255,255,255,.06)}@media(max-width:760px){.cards article,.closing{grid-template-columns:1fr}}</style>
